import requests
import base64

SERVER_ADDRESS = "http://localhost:15672"
USERNAME = "guest"
PASSWORD = "guest"

def setup_vhost(vhost_name):
    vhost_url = SERVER_ADDRESS + "/api/vhosts/" + vhost_name
    vhost_headers = {
        "Authorization": "Basic " + base64.b64encode(f"{USERNAME}:{PASSWORD}".encode()).decode()
    }
    response = requests.put(vhost_url, headers=vhost_headers)
    return response.status_code

def setup_user(username, password):
    user_url = SERVER_ADDRESS + "/api/users/" + username
    user_data = {
        "password": password,
        "tags": ""
    }
    user_headers = {
        "Authorization": "Basic " + base64.b64encode(f"{USERNAME}:{PASSWORD}".encode()).decode(),
        "Content-Type": "application/json"
    }
    response = requests.put(user_url, json=user_data, headers=user_headers)
    return response.status_code

def set_permissions(vhost_name, username):
    permissions_url = SERVER_ADDRESS + "/api/permissions/" + vhost_name + "/" + username
    permissions_data = {
        "configure": ".*",
        "write": ".*",
        "read": ".*"
    }
    permissions_headers = {
        "Authorization": "Basic " + base64.b64encode(f"{USERNAME}:{PASSWORD}".encode()).decode(),
        "Content-Type": "application/json"
    }
    response = requests.put(permissions_url, json=permissions_data, headers=permissions_headers)
    return response.status_code

vhost_name = "my_vhost"
